/**
 * Unit tests for CourseStudentService
 * Tests enrollment cancellation (soft delete) and cancel preview functionality
 */

import { describe, it, expect, jest, beforeEach } from '@jest/globals';
import mongoose from 'mongoose';

// Use any type for mocks to avoid TypeScript strict mode issues with jest
/* eslint-disable @typescript-eslint/no-explicit-any */

// Mock all dependencies before importing the service
jest.mock('@/infrastructure/database/models/course_student.model', () => ({
  CourseStudentModel: {
    findById: jest.fn(),
    findOne: jest.fn(),
    countDocuments: jest.fn(),
    aggregate: jest.fn(),
    find: jest.fn(),
  },
  CourseStudentStatus: {},
}));

jest.mock('@/infrastructure/database/models/payment.model', () => ({
  PaymentModel: {
    countDocuments: jest.fn(),
  },
}));

jest.mock('@/infrastructure/database/models/dat_session.model', () => ({
  DatSessionModel: {
    countDocuments: jest.fn(),
    aggregate: jest.fn(),
  },
}));

jest.mock('@/infrastructure/logging/logger', () => ({
  __esModule: true,
  default: {
    info: jest.fn(),
    warn: jest.fn(),
    error: jest.fn(),
  },
}));

// Import models after mocking
import { CourseStudentModel } from '@/infrastructure/database/models/course_student.model';
import { PaymentModel } from '@/infrastructure/database/models/payment.model';
import { DatSessionModel } from '@/infrastructure/database/models/dat_session.model';
import { CourseStudentService } from '@/application/services/course-student.service';
import { AppError } from '@/domain/exceptions/app-error';

describe('CourseStudentService', () => {
  let service: CourseStudentService;

  const mockEnrollmentId = '507f1f77bcf86cd799439011';
  const mockUserId = '507f1f77bcf86cd799439012';

  const createMockEnrollment = (status: string) => ({
    _id: new mongoose.Types.ObjectId(mockEnrollmentId),
    student_id: new mongoose.Types.ObjectId(),
    course_id: new mongoose.Types.ObjectId(),
    status,
    save: jest.fn(),
  });

  beforeEach(() => {
    service = new CourseStudentService();
    jest.clearAllMocks();
  });

  describe('cancelEnrollment', () => {
    it('should throw NotFoundException when enrollment does not exist', async () => {
      (CourseStudentModel.findById as jest.Mock).mockResolvedValue(null);

      await expect(
        service.cancelEnrollment(mockEnrollmentId, 'Test reason', mockUserId)
      ).rejects.toThrow(AppError);
      await expect(
        service.cancelEnrollment(mockEnrollmentId, 'Test reason', mockUserId)
      ).rejects.toThrow('Enrollment not found');
    });

    it('should throw BadRequestException when enrollment is already canceled', async () => {
      (CourseStudentModel.findById as jest.Mock).mockResolvedValue(
        createMockEnrollment('canceled')
      );

      await expect(
        service.cancelEnrollment(mockEnrollmentId, 'Test reason', mockUserId)
      ).rejects.toThrow(AppError);
      await expect(
        service.cancelEnrollment(mockEnrollmentId, 'Test reason', mockUserId)
      ).rejects.toThrow('Enrollment đã bị hủy trước đó');
    });

    it('should successfully cancel an active enrollment', async () => {
      const mockEnrollment = createMockEnrollment('studying');
      const savedEnrollment = {
        ...mockEnrollment,
        status: 'canceled',
        canceled_at: new Date(),
        cancel_reason: 'Test reason',
        canceled_by: new mongoose.Types.ObjectId(mockUserId),
      };
      mockEnrollment.save.mockResolvedValue(savedEnrollment);

      (CourseStudentModel.findById as jest.Mock).mockResolvedValue(mockEnrollment);

      const result = await service.cancelEnrollment(
        mockEnrollmentId,
        'Test reason',
        mockUserId
      );

      expect(mockEnrollment.save).toHaveBeenCalled();
      expect(result.status).toBe('canceled');
      expect(result.cancel_reason).toBe('Test reason');
      expect(result.canceled_by).toBeDefined();
    });

    it('should allow empty reason string', async () => {
      const mockEnrollment = createMockEnrollment('studying');
      mockEnrollment.save.mockResolvedValue({
        _id: mockEnrollment._id,
        status: 'canceled',
        cancel_reason: '',
      });

      (CourseStudentModel.findById as jest.Mock).mockResolvedValue(mockEnrollment);

      const result = await service.cancelEnrollment(mockEnrollmentId, '', mockUserId);

      expect(mockEnrollment.save).toHaveBeenCalled();
      expect(result.status).toBe('canceled');
    });
  });

  describe('getCancelPreview', () => {
    it('should throw NotFoundException when enrollment does not exist', async () => {
      (CourseStudentModel.findById as jest.Mock).mockResolvedValue(null);

      await expect(service.getCancelPreview(mockEnrollmentId)).rejects.toThrow(AppError);
      await expect(service.getCancelPreview(mockEnrollmentId)).rejects.toThrow(
        'Enrollment not found'
      );
    });

    it('should throw BadRequestException when enrollment is already canceled', async () => {
      (CourseStudentModel.findById as jest.Mock).mockResolvedValue(
        createMockEnrollment('canceled')
      );

      await expect(service.getCancelPreview(mockEnrollmentId)).rejects.toThrow(AppError);
      await expect(service.getCancelPreview(mockEnrollmentId)).rejects.toThrow(
        'Enrollment đã bị hủy trước đó'
      );
    });

    it('should return empty warnings when no payments or DAT sessions exist', async () => {
      (CourseStudentModel.findById as jest.Mock).mockResolvedValue(
        createMockEnrollment('studying')
      );
      (PaymentModel.countDocuments as jest.Mock).mockResolvedValue(0);
      (DatSessionModel.countDocuments as jest.Mock).mockResolvedValue(0);
      (DatSessionModel.aggregate as jest.Mock).mockResolvedValue([]);

      const result = await service.getCancelPreview(mockEnrollmentId);

      expect(result.hasPayments).toBe(false);
      expect(result.hasDatSessions).toBe(false);
      expect(result.datCompleted).toBe(false);
      expect(result.warnings).toEqual([]);
    });

    it('should return warning when payments exist', async () => {
      (CourseStudentModel.findById as jest.Mock).mockResolvedValue(
        createMockEnrollment('studying')
      );
      (PaymentModel.countDocuments as jest.Mock).mockResolvedValue(2);
      (DatSessionModel.countDocuments as jest.Mock).mockResolvedValue(0);
      (DatSessionModel.aggregate as jest.Mock).mockResolvedValue([]);

      const result = await service.getCancelPreview(mockEnrollmentId);

      expect(result.hasPayments).toBe(true);
      expect(result.paymentCount).toBe(2);
      expect(result.warnings).toContain(
        'Đã có 2 khoản thanh toán — sẽ được giữ lại trong lịch sử'
      );
    });

    it('should return warning when DAT is completed (>= 810km)', async () => {
      (CourseStudentModel.findById as jest.Mock).mockResolvedValue(
        createMockEnrollment('studying')
      );
      (PaymentModel.countDocuments as jest.Mock).mockResolvedValue(0);
      (DatSessionModel.countDocuments as jest.Mock).mockResolvedValue(5);
      (DatSessionModel.aggregate as jest.Mock).mockResolvedValue([
        { _id: null, totalKm: 850 },
      ]);

      const result = await service.getCancelPreview(mockEnrollmentId);

      expect(result.hasDatSessions).toBe(true);
      expect(result.datCompleted).toBe(true);
      expect(result.totalDatKm).toBe(850);
      expect(result.warnings).toContain(
        'Đã hoàn thành DAT (850km) — tiến độ sẽ được giữ trong lịch sử'
      );
    });

    it('should return multiple warnings when both payments and DAT exist', async () => {
      (CourseStudentModel.findById as jest.Mock).mockResolvedValue(
        createMockEnrollment('studying')
      );
      (PaymentModel.countDocuments as jest.Mock).mockResolvedValue(3);
      (DatSessionModel.countDocuments as jest.Mock).mockResolvedValue(10);
      (DatSessionModel.aggregate as jest.Mock).mockResolvedValue([
        { _id: null, totalKm: 900 },
      ]);

      const result = await service.getCancelPreview(mockEnrollmentId);

      expect(result.hasPayments).toBe(true);
      expect(result.hasDatSessions).toBe(true);
      expect(result.datCompleted).toBe(true);
      expect(result.warnings.length).toBe(2);
      expect(result.warnings).toContain(
        'Đã có 3 khoản thanh toán — sẽ được giữ lại trong lịch sử'
      );
      expect(result.warnings).toContain(
        'Đã hoàn thành DAT (900km) — tiến độ sẽ được giữ trong lịch sử'
      );
    });

    it('should not mark DAT as completed when km < 810', async () => {
      (CourseStudentModel.findById as jest.Mock).mockResolvedValue(
        createMockEnrollment('studying')
      );
      (PaymentModel.countDocuments as jest.Mock).mockResolvedValue(0);
      (DatSessionModel.countDocuments as jest.Mock).mockResolvedValue(5);
      (DatSessionModel.aggregate as jest.Mock).mockResolvedValue([
        { _id: null, totalKm: 500 },
      ]);

      const result = await service.getCancelPreview(mockEnrollmentId);

      expect(result.datCompleted).toBe(false);
      expect(result.warnings).toEqual([]);
    });

    it('should handle empty aggregate result', async () => {
      (CourseStudentModel.findById as jest.Mock).mockResolvedValue(
        createMockEnrollment('studying')
      );
      (PaymentModel.countDocuments as jest.Mock).mockResolvedValue(0);
      (DatSessionModel.countDocuments as jest.Mock).mockResolvedValue(0);
      (DatSessionModel.aggregate as jest.Mock).mockResolvedValue([]);

      const result = await service.getCancelPreview(mockEnrollmentId);

      expect(result.totalDatKm).toBe(0);
      expect(result.datCompleted).toBe(false);
    });
  });

  describe('getEnrollmentById', () => {
    it('should return enrollment when found with activeOnly=false', async () => {
      const mockEnrollment = {
        _id: new mongoose.Types.ObjectId(mockEnrollmentId),
        status: 'studying',
      };
      (CourseStudentModel.findOne as jest.Mock).mockResolvedValue(mockEnrollment);

      const result = await service.getEnrollmentById(mockEnrollmentId, false);

      expect(CourseStudentModel.findOne).toHaveBeenCalledWith(
        expect.objectContaining({ _id: expect.any(mongoose.Types.ObjectId) })
      );
      expect(result).toEqual(mockEnrollment);
    });

    it('should filter out canceled enrollments when activeOnly=true', async () => {
      const mockEnrollment = {
        _id: new mongoose.Types.ObjectId(mockEnrollmentId),
        status: 'canceled',
      };
      (CourseStudentModel.findOne as jest.Mock).mockResolvedValue(mockEnrollment);

      const result = await service.getEnrollmentById(mockEnrollmentId, true);

      expect(CourseStudentModel.findOne).toHaveBeenCalledWith(
        expect.objectContaining({
          _id: expect.any(mongoose.Types.ObjectId),
          status: { $ne: 'canceled' },
        })
      );
    });

    it('should return null when enrollment not found', async () => {
      (CourseStudentModel.findOne as jest.Mock).mockResolvedValue(null);

      const result = await service.getEnrollmentById(mockEnrollmentId);

      expect(result).toBeNull();
    });
  });

  describe('canEnrollNewCourse', () => {
    const mockStudentId = '507f1f77bcf86cd799439013';

    it('should return true when no active enrollments exist', async () => {
      (CourseStudentModel.countDocuments as jest.Mock).mockResolvedValue(0);

      const result = await service.canEnrollNewCourse(mockStudentId);

      expect(result).toBe(true);
    });

    it('should return false when active enrollments exist', async () => {
      (CourseStudentModel.countDocuments as jest.Mock).mockResolvedValue(1);

      const result = await service.canEnrollNewCourse(mockStudentId);

      expect(result).toBe(false);
    });

    it('should exclude specific enrollment when excludeEnrollmentId provided', async () => {
      const excludeId = '507f1f77bcf86cd799439014';
      (CourseStudentModel.countDocuments as jest.Mock).mockResolvedValue(0);

      await service.canEnrollNewCourse(mockStudentId, excludeId);

      expect(CourseStudentModel.countDocuments).toHaveBeenCalledWith(
