      expect(result.datCompleted).toBe(true);
      expect(result.totalDatKm).toBe(850);
      expect(result.warnings).toContain(
        'Đã hoàn thành DAT (850km) — tiến độ sẽ được giữ trong lịch sử'
      );
    });

    it('should return multiple warnings when both payments and DAT exist', async () => {
      mockCourseStudentFindById.mockResolvedValue(createMockEnrollment('studying'));
      mockPaymentCountDocuments.mockResolvedValue(3);
      mockDatSessionCountDocuments.mockResolvedValue(10);
      mockDatSessionAggregate.mockResolvedValue([{ _id: null, totalKm: 900 }]);

      const result = await service.getCancelPreview(mockEnrollmentId);

      expect(result.hasPayments).toBe(true);
      expect(result.hasDatSessions).toBe(true);
      expect(result.datCompleted).toBe(true);
      expect(result.warnings.length).toBe(2);
      expect(result.warnings).toContain(
        'Đã có 3 khoản thanh toán — sẽ được giữ lại trong lịch sử'
      );
      expect(result.warnings).toContain(
        'Đã hoàn thành DAT (900km) — tiến độ sẽ được giữ trong lịch sử'
      );
    });

    it('should not mark DAT as completed when km < 810', async () => {
      mockCourseStudentFindById.mockResolvedValue(createMockEnrollment('studying'));
      mockPaymentCountDocuments.mockResolvedValue(0);
      mockDatSessionCountDocuments.mockResolvedValue(5);
