import { describe, it, expect } from '@jest/globals';

describe('Course validation', () => {
  it('should require end_date >= start_date', () => {
    const startDate = '2026-06-01';
    const endDate = '2026-05-01';
    const isValid = !endDate || endDate >= startDate;
    expect(isValid).toBe(false);
  });

  it('should allow valid date range', () => {
    const startDate = '2026-05-01';
    const endDate = '2026-06-01';
    const isValid = !endDate || endDate >= startDate;
    expect(isValid).toBe(true);
  });

  it('should allow course with only start_date', () => {
    const startDate = '2026-05-01';
    const endDate = (null as unknown) as string;
    const isValid = !endDate || endDate >= startDate;
    expect(isValid).toBe(true);
  });
});

describe('max_students validation', () => {
  it('should reject assignment exceeding max_students', () => {
    const maxStudents = 5;
    const currentCount = 5;
    const newAssignments = 2;
    const isValid = (currentCount + newAssignments) <= maxStudents;
    expect(isValid).toBe(false);
  });

  it('should allow assignment within max_students', () => {
    const maxStudents = 5;
    const currentCount = 3;
    const newAssignments = 2;
    const isValid = (currentCount + newAssignments) <= maxStudents;
    expect(isValid).toBe(true);
  });
});

